import math
from functools import reduce


class Solution:
    def maxLength(self, nums):
        n = len(nums)
        best = 0
        for i in range(n):
            for j in range(i, n):
                window = nums[i:j + 1]
                prod = reduce(lambda a, b: a * b, window, 1)
                g = reduce(math.gcd, window)
                l = reduce(lambda a, b: a * b // math.gcd(a, b), window)
                if prod == l * g:
                    best = max(best, j - i + 1)
        return best

