var maxLength = function(nums) {
    function gcd(a, b) { while (b) { [a, b] = [b, a % b]; } return a; }
    const n = nums.length;
    let best = 0;
    for (let i = 0; i < n; i++) {
        let prod = 1n, g = 0n, l = 1n;
        for (let j = i; j < n; j++) {
            const v = BigInt(nums[j]);
            prod *= v;
            g = gcd(g, v);
            l = (l * v) / gcd(l, v);
            if (prod === l * g) best = Math.max(best, j - i + 1);
        }
    }
    return best;
};
